  window.EXTRA_READ_STORIES.push(...[{"id":"pt-manha","title":"Manhã na cidade","subtitle":"Morning in the city","trail":"green-circle","categoryId":"pt","sentences":[{"foreign":"Bom dia!","en":"Good morning!"},{"foreign":"Oi. Acabei de chegar.","en":"Hi. I just arrived."},{"foreign":"Está frio, mas o sol brilha.","en":"It is cold, but the sun is shining."},{"foreign":"Pego a bicicleta compartilhada até a saída do metrô.","en":"I take the shared bike to the metro exit."},{"foreign":"Com licença, onde fica a parada do bonde?","en":"Excuse me, where is the tram stop?"},{"foreign":"Em frente, depois do validador, em direção à plataforma.","en":"Straight ahead, after the validator, toward the platform."},{"foreign":"Obrigado. A linha do metrô está funcionando agora?","en":"Thanks. Is the metro line running now?"},{"foreign":"Sim. Veja o horário de ônibus, ou pegue o ônibus municipal se tiver pressa.","en":"Yes. Check the bus timetable, or take the city bus if you're in a hurry."},{"foreign":"Muito obrigado. Tenha um bom dia!","en":"Thank you. Have a nice day!"},{"foreign":"Sem problema. Boa sorte!","en":"No problem. Good luck!"},{"foreign":"Perto da saída do metrô tem bicicleta compartilhada e Bilhete Único.","en":"Near the metro exit there is a shared bike and Bilhete Único."}],"glosses":{"bicicleta compartilhada":"shared bike","saída do metrô":"metro exit","bonde":"tram","validador":"ticket validator","plataforma":"platform","linha do metrô":"metro line","horário de ônibus":"bus timetable","ônibus municipal":"city bus","Bilhete Único":"single ticket / transport card"}},{"id":"pt-cafe","title":"Um café, por favor","subtitle":"Ordering coffee","trail":"green-circle","categoryId":"pt","sentences":[{"foreign":"Oi! Tem lugar na varanda gourmet no balcão?","en":"Hi! Is there a seat on the terrace at the counter?"},{"foreign":"Sim. Quer o menu do almoço ou a carta de vinhos?","en":"Yes. Would you like the lunch menu or the wine list?"},{"foreign":"Um pingado, por favor. Ou um cappuccino.","en":"A coffee with a splash of milk, please. Or a cappuccino."},{"foreign":"Quer também o café da manhã completo? Temos água mineral com gás e pão de queijo mineiro.","en":"Would you also like the full breakfast? We have sparkling mineral water and Minas cheese bread."},{"foreign":"O que o senhor recomenda? O prato do dia ou o prato feito?","en":"What do you recommend? The dish of the day or the set lunch?"},{"foreign":"Um misto quente, ou aperitivo com pastel de feira. Depois bolo de cenoura ou sorvete artesanal.","en":"A toasted ham and cheese, or an aperitif with street-fair pastry. Then carrot cake or artisanal ice cream."},{"foreign":"Um misto quente, obrigado. E um chopp para o meu amigo.","en":"A toasted sandwich, thanks. And a draught beer for my friend."},{"foreign":"O garçom traz a conta por favor quando quiser. Gorjeta opcional.","en":"The waiter will bring the bill please when you want. Tip optional."},{"foreign":"Perfeito. Tenha um bom dia!","en":"Perfect. Have a nice day!"}],"glosses":{"varanda gourmet":"outdoor terrace seating","balcão":"bar counter","menu do almoço":"lunch menu","carta de vinhos":"wine list","pingado":"coffee with a splash of milk","cappuccino":"cappuccino","café da manhã completo":"full breakfast","água mineral com gás":"sparkling mineral water","pão de queijo mineiro":"Minas cheese bread","prato do dia":"dish of the day","prato feito":"set lunch","misto quente":"toasted ham and cheese","aperitivo":"aperitif","pastel de feira":"street-fair pastry","bolo de cenoura":"carrot cake","sorvete artesanal":"artisanal ice cream","chopp":"draught beer","garçom":"waiter","a conta por favor":"the bill please","gorjeta opcional":"optional tip"}},{"id":"pt-trem","title":"No trem","subtitle":"On the train","trail":"green-circle","categoryId":"pt","sentences":[{"foreign":"Esse trem urbano vai para São Paulo? É a CPTM?","en":"Does this urban train go to São Paulo? Is it the CPTM?"},{"foreign":"Sim, exatamente. Próxima saída em dez minutos na estação de metrô.","en":"Yes, exactly. Next departure in ten minutes at the metro station."},{"foreign":"Onde compro o bilhete? Você tem Bilhete Único?","en":"Where do I buy the ticket? Do you have Bilhete Único?"},{"foreign":"No app ou no balcão. Bilhete de ida e volta serve. Lembre da recarga de bilhete.","en":"In the app or at the counter. A return ticket works. Remember the ticket top-up."},{"foreign":"Bilhete de ida e volta, por favor. Depois do validador, qual plataforma?","en":"Return ticket, please. After the validator, which platform?"},{"foreign":"Plataforma três. Cuidado com a baldeação e a conexão. Ou pegue o metrô.","en":"Platform three. Watch the transfer and the connection. Or take the metro."},{"foreign":"Quanto tempo demora? Tem atraso de trem no horário de pico.","en":"How long does it take? There is train delay in rush hour."},{"foreign":"Umas duas horas. No estacionamento integrado você deixa o carro.","en":"About two hours. At the park and ride you leave the car."},{"foreign":"Ótimo. Boa viagem!","en":"Great. Have a good trip!"}],"glosses":{"trem urbano":"urban train","CPTM":"CPTM train","estação de metrô":"metro station","Bilhete Único":"single ticket / transport card","bilhete de ida e volta":"return ticket","recarga de bilhete":"ticket top-up","validador":"ticket validator","plataforma":"platform","baldeação":"transfer","conexão":"connection","metrô":"metro","atraso de trem":"train delay","estacionamento integrado":"park and ride"}},{"id":"pt-biblioteca","title":"Na biblioteca","subtitle":"At the library","trail":"blue-square","categoryId":"pt","sentences":[{"foreign":"Oi, procuro um lugar quieto na biblioteca universitária do campus universitário.","en":"Hi, I'm looking for a quiet place in the university library on the university campus."},{"foreign":"Em cima tem lugares. O auditório está ocupado, e a aula prática também.","en":"Upstairs there are seats. The lecture hall is busy, and the practical class too."},{"foreign":"Até que horas vocês ficam abertos?","en":"How late are you open?"},{"foreign":"Até as vinte e uma. A sala de laboratório fecha mais cedo.","en":"Until nine. The lab room closes earlier."},{"foreign":"Posso pegar livros com a carteirinha de estudante? Moro em residência estudantil.","en":"Can I borrow books with a student ID? I live in student housing."},{"foreign":"Sim. Precisa de apostila, grade curricular, ou ajuda na prova parcial?","en":"Yes. Do you need course notes, the curriculum, or help on the mid-term?"},{"foreign":"Talvez depois. Primeiro monitoria com um amigo. A secretaria acadêmica cuida do início do semestre.","en":"Maybe later. First tutoring with a friend. The academic office handles the start of the semester."},{"foreign":"Pense no trabalho de conclusão. A orientação acadêmica ajuda com a bolsa de estudos e o curso de graduação.","en":"Think about the thesis. Academic advising helps with the scholarship and the degree course."},{"foreign":"Obrigado. Espero terminar a graduação, o doutorado vem depois. Intercâmbio no ano que vem, talvez.","en":"Thanks. I hope to finish undergrad. The PhD comes later. Exchange next year, maybe."},{"foreign":"Boa sorte na prova!","en":"Good luck on the exam!"}],"glosses":{"biblioteca universitária":"university library","campus universitário":"university campus","auditório":"lecture hall","aula prática":"practical class","sala de laboratório":"lab room","carteirinha de estudante":"student ID","residência estudantil":"student housing","apostila":"course notes","grade curricular":"curriculum","prova parcial":"mid-term exam","monitoria":"tutoring","secretaria acadêmica":"academic office","início do semestre":"start of semester","trabalho de conclusão":"thesis / final paper","orientação acadêmica":"academic advising","bolsa de estudos":"scholarship","curso de graduação":"degree course","graduação":"undergraduate degree","doutorado":"PhD","intercâmbio":"exchange programme"}},{"id":"pt-mercado","title":"No mercado","subtitle":"At the market","trail":"blue-square","categoryId":"pt","sentences":[{"foreign":"Oi. Tem liquidação no supermercado hoje?","en":"Hi. Is there a sale at the supermarket today?"},{"foreign":"Sim, e promoção na feira orgânica. Congelados ficam na seção.","en":"Yes, and a promotion at the organic market. Frozen foods are in the department."},{"foreign":"Quanto custa esse queijo?","en":"How much is this cheese?"},{"foreign":"Trinta reais. Quer uma sacola reutilizável?","en":"Thirty reais. Would you like a reusable bag?"},{"foreign":"Sim, por favor. Levo dois queijos e pão da padaria.","en":"Yes, please. I'll take two cheeses and bread from the bakery."},{"foreign":"O carrinho de compras está ali. Veja a etiqueta de preço e o código de barras.","en":"The shopping trolley is over there. Check the price tag and barcode."},{"foreign":"Obrigado. Posso pagar no caixa com cartão fidelidade, ou PIX, ou retire na loja?","en":"Thanks. Can I pay at the checkout with the loyalty card, or PIX, or click and collect?"},{"foreign":"Os dois. Aqui está a nota fiscal. O hipermercado também tem drogaria.","en":"Either. Here's the receipt. The hypermarket also has a drugstore."},{"foreign":"Ótimo. Faço as compras no autoatendimento. Tem desconto no total. Tchau!","en":"Great. I'm doing the groceries self-service. There's a discount on the total. Bye!"}],"glosses":{"liquidação":"sale","supermercado":"supermarket","promoção":"promotion","feira orgânica":"organic market","congelados":"frozen foods","seção":"department","sacola reutilizável":"reusable bag","padaria":"bakery","carrinho de compras":"shopping trolley","etiqueta de preço":"price tag","código de barras":"barcode","caixa":"checkout","cartão fidelidade":"loyalty card","PIX":"PIX (instant payment)","retire na loja":"click and collect","nota fiscal":"receipt","hipermercado":"hypermarket","drogaria":"drugstore","compras":"groceries","autoatendimento":"self-service","desconto":"discount / sale"}},{"id":"pt-amigos","title":"Novos amigos","subtitle":"New friends","trail":"blue-square","categoryId":"pt","sentences":[{"foreign":"Oi, meu nome é Sam.","en":"Hi, my name is Sam."},{"foreign":"Prazer. Eu sou Noor. Beijo no rosto ou aperto de mão?","en":"Nice to meet you. I'm Noor. A kiss on the cheek or a handshake?"},{"foreign":"De onde você é?","en":"Where are you from?"},{"foreign":"Do Canadá, mas agora moro aqui. E você?","en":"From Canada, but I live here now. And you?"},{"foreign":"Daqui. O que você estuda?","en":"From here. What do you study?"},{"foreign":"Informática. Você tem planos para o fim de semana em família?","en":"Computer science. Do you have plans for the family weekend?"},{"foreign":"Sim. Uma noite fora e uma festa com amigos de longa data. Vem no happy hour?","en":"Yes. A night out and a party with long-time friends. Coming to happy hour?"},{"foreign":"Com certeza! Gosto de conversa no meu círculo de amigos. Amanhã café com amigos?","en":"Of course! I like conversation in my circle of friends. Coffee with friends tomorrow?"},{"foreign":"Demais. É o aniversário dele, e uma reunião de amigos na vizinhança.","en":"Awesome. It's his birthday, and a friends reunion in the neighbourhood."},{"foreign":"Perfeito. Almoço em família no domingo, depois brinde de despedida pro padrinho de casamento e a madrinha de casamento. Tem grupo de WhatsApp e discussão sobre casamento civil. Até logo!","en":"Perfect. Family lunch on Sunday, then a farewell toast for the wedding godfather and godmother. There's a WhatsApp group and a discussion about civil wedding. See you!"}],"glosses":{"beijo no rosto":"kiss on the cheek","aperto de mão":"handshake","fim de semana em família":"family weekend","noite fora":"night out","festa":"party","amigos de longa data":"long-time friends","happy hour":"happy hour","conversa":"conversation","círculo de amigos":"circle of friends","café com amigos":"coffee with friends","aniversário":"birthday","reunião de amigos":"friends reunion","vizinhança":"neighbourhood community","almoço em família":"family lunch","brinde de despedida":"farewell toast","padrinho de casamento":"wedding godfather","madrinha de casamento":"wedding godmother","casamento civil":"civil wedding","discussão":"discussion","grupo de WhatsApp":"WhatsApp group"}},{"id":"pt-trabalho","title":"Primeiro dia de trabalho","subtitle":"First day at work","trail":"black-diamond","categoryId":"pt","sentences":[{"foreign":"Bem-vindo ao time, Sam. Este é o escritório aberto.","en":"Welcome to the team, Sam. This is the open-plan office."},{"foreign":"Obrigado. Estou um pouco nervoso. É contrato CLT ou contrato temporário?","en":"Thanks. I'm a bit nervous. Is it a permanent employment contract or temporary?"},{"foreign":"Contrato CLT. O chefe de setor apresenta o projeto depois do intervalo de almoço.","en":"Permanent contract. The department head presents the project after lunch break."},{"foreign":"Onde posso deixar minhas coisas?","en":"Where can I put my things?"},{"foreign":"Aqui perto da janela. Um colega de trabalho te passa o acesso. O refeitório fica no térreo.","en":"Here by the window. A colleague will give you access. The staff canteen is on the ground floor."},{"foreign":"Se tiver dúvidas, pergunta. Vamos falar da convenção coletiva e do home office.","en":"If you have questions, ask. We'll talk about the collective agreement and remote work."},{"foreign":"Entendi. Quem é meu contato hoje? A avaliação de desempenho vem depois, acho.","en":"Understood. Who is my contact today? The performance review comes later, I think."},{"foreign":"Sou eu. O holerite chega no dia 15. Pelo menos o salário mínimo, mais bônus possível.","en":"That's me. The payslip arrives on the 15th. At least the minimum wage, plus a possible bonus."},{"foreign":"Ok. E férias coletivas? Treinamento? Horário de trabalho e comissão de fábrica?","en":"Ok. And collective leave? Training? Working hours and works council?"},{"foreign":"Sim, tudo no dossiê. Perfil de competências também. Sem desemprego se der certo, e tem sindicato. Boa sorte!","en":"Yes, everything is in the file. Competency profile too. No unemployment if things go well, and there's a union. Good luck!"}],"glosses":{"escritório aberto":"open-plan office","contrato CLT":"permanent employment contract","contrato temporário":"temporary contract","chefe de setor":"department head","intervalo de almoço":"lunch break","colega de trabalho":"colleague","refeitório":"staff canteen","térreo":"ground floor","convenção coletiva":"collective agreement","home office":"remote work","avaliação de desempenho":"performance review","holerite":"payslip","salário mínimo":"minimum wage","bônus":"bonus","férias coletivas":"collective leave","treinamento":"training","horário de trabalho":"working hours","comissão de fábrica":"works council","perfil de competências":"competency profile","desemprego":"unemployment","sindicato":"trade union"}},{"id":"pt-medico","title":"No médico","subtitle":"At the doctor's","trail":"black-diamond","categoryId":"pt","sentences":[{"foreign":"Bom dia. O senhor tem consulta médica com o médico de família?","en":"Good morning. Do you have a medical appointment with the family doctor?"},{"foreign":"Sim. Aqui está o cartão do SUS e o CPF.","en":"Yes. Here's the SUS card and tax ID."},{"foreign":"O que está sentindo?","en":"What's wrong?"},{"foreign":"Estou com dor de garganta há dois dias e um pouco de febre.","en":"I've had a sore throat for two days and a bit of fever."},{"foreign":"O técnico de enfermagem te chama na sala de espera. Vamos ver o prontuário no consultório.","en":"The nursing technician will call you in the waiting room. We'll look at the medical record in the consultation room."},{"foreign":"Parece uma infecção leve. Precisa de receita médica e antibiótico?","en":"It looks like a mild infection. Do you need a medical prescription and an antibiotic?"},{"foreign":"Ainda não. Repouso, água e, se precisar, a farmácia de plantão.","en":"Not yet. Rest, water, and the on-duty pharmacy if needed."},{"foreign":"E o SUS e o convênio médico?","en":"And the Unified Health System and private health plan?"},{"foreign":"Vamos marcar o retorno. Se piorar. UPA, não só o especialista. Ou encaminhamento.","en":"We'll schedule the follow-up. If it gets worse. Urgent care unit, not only the specialist. Or a referral."},{"foreign":"Obrigado. Exame de sangue ou raio-X? Campanha de vacinação em dia?","en":"Thanks. Blood test or X-ray? Vaccination campaign up to date?"},{"foreign":"Não hoje. Volte se precisar.","en":"Not today. Come back if needed."}],"glosses":{"consulta médica":"medical appointment","médico de família":"family doctor","cartão do SUS":"SUS card","CPF":"tax ID number","técnico de enfermagem":"nursing technician","sala de espera":"waiting room","prontuário":"medical record","consultório":"consultation room","receita médica":"medical prescription","antibiótico":"antibiotic","farmácia de plantão":"on-duty pharmacy","SUS":"Unified Health System","convênio médico":"private health plan","retorno":"follow-up","UPA":"urgent care unit (UPA)","especialista":"specialist","encaminhamento":"referral","exame de sangue":"blood test","raio-X":"X-ray","campanha de vacinação":"vaccination campaign"}},{"id":"pt-moradia","title":"Procurando um quarto","subtitle":"Looking for a room","trail":"black-diamond","categoryId":"pt","sentences":[{"foreign":"Oi, ligo sobre a kitnet anunciada na internet.","en":"Hi, I'm calling about the studio advertised online."},{"foreign":"Sim, ainda está livre. Quando quer ver?","en":"Yes, it's still free. When would you like to see it?"},{"foreign":"Hoje à tarde, por volta das três.","en":"This afternoon, around three."},{"foreign":"Certo. É um apartamento mobiliado em república, em bairro residencial.","en":"Fine. It's a furnished apartment in shared student housing, in a residential neighbourhood."},{"foreign":"Tem elevador? Tenho pouca coisa na mudança. O térreo está livre?","en":"Is there an elevator? I have little for the move. Is the ground floor free?"},{"foreign":"Sem elevador. O locador traz o contrato de locação e o certificado energético. A caução é um mês de aluguel mensal.","en":"No elevator. The landlord brings the rental contract and energy certificate. The deposit is one month's rent."},{"foreign":"E o síndico? O seguro residencial? O relógio de luz?","en":"And the building manager? Home insurance? The electricity meter?"},{"foreign":"Tudo certo. O porteiro tem as chaves e o interfone. Aqui um exemplo de recibo de aluguel.","en":"Everything's fine. The doorman has the keys and the intercom. Here's a sample rent receipt."},{"foreign":"Perfeito. Avise se o vizinho de porta reclamar do barulho, e onde ficam a lixeira e a lavanderia.","en":"Perfect. Let me know if the next-door neighbour complains about noise, and where the rubbish bin and laundry are."}],"glosses":{"kitnet":"studio apartment","apartamento mobiliado":"furnished apartment","república":"shared student housing","bairro residencial":"residential neighbourhood","mudança":"moving house","térreo":"ground floor","locador":"landlord","contrato de locação":"rental contract","certificado energético":"energy certificate","caução":"security deposit","aluguel mensal":"monthly rent","síndico":"building manager","seguro residencial":"home insurance","relógio de luz":"electricity meter","porteiro":"doorman","interfone":"door intercom","recibo de aluguel":"rent receipt","vizinho de porta":"next-door neighbour","lixeira":"rubbish bin","lavanderia":"laundry"}},{"id":"pt-noticias","title":"Greve no metrô","subtitle":"Metro strike","trail":"double-black-diamond","categoryId":"pt","sentences":[{"foreign":"Você viu as notícias de manhã?","en":"Did you see the news this morning?"},{"foreign":"Não, o que aconteceu?","en":"No, what happened?"},{"foreign":"Amanhã tem greve de transporte. Metrô, bonde e às vezes a CPTM.","en":"Tomorrow there's a transport strike. Metro, tram, and sometimes the CPTM."},{"foreign":"Então os trens não rodam?","en":"So the trains don't run?"},{"foreign":"Muitos param. Tem atraso de trem e o ônibus do aeroporto fica lotado.","en":"Many stop. There is train delay and the airport shuttle is full."},{"foreign":"Pego a bicicleta compartilhada, mesmo se chover. Ou faço home office.","en":"I'll take the shared bike, even if it rains. Or I'll do remote work."},{"foreign":"Esperto. Você fala primeiro com o chefe de setor?","en":"Smart. Will you talk to the department head first?"},{"foreign":"Sim, e confiro o saldo para um táxi do aeroporto. A estação de metrô vai ser um caos.","en":"Yes, and I'll check the balance for an airport taxi. The metro station will be chaos."},{"foreign":"Lembre do validador e do Bilhete Único se sair mesmo assim.","en":"Remember the validator and Bilhete Único if you go out anyway."},{"foreign":"Ok. Me avisa se virar voo atrasado.","en":"Ok. Let me know if it becomes a delayed flight."}],"glosses":{"greve de transporte":"transport strike","metrô":"metro","bonde":"tram","CPTM":"CPTM train","atraso de trem":"train delay","ônibus do aeroporto":"airport shuttle","bicicleta compartilhada":"shared bike","home office":"remote work","chefe de setor":"department head","saldo":"balance","táxi do aeroporto":"airport taxi","estação de metrô":"metro station","validador":"ticket validator","Bilhete Único":"single ticket / transport card","voo atrasado":"delayed flight"}},{"id":"pt-debate","title":"Um debate rápido","subtitle":"A short debate","trail":"double-black-diamond","categoryId":"pt","sentences":[{"foreign":"Eu acho o transporte público muito importante.","en":"I think public transport is really important."},{"foreign":"Por quê?","en":"Why?"},{"foreign":"Porque nem todo mundo tem carro, e as tarifas bancárias no financiamento imobiliário já pesam.","en":"Because not everyone has a car, and bank fees on a mortgage already weigh heavy."},{"foreign":"Mas os ônibus estão sempre cheios e atrasados. O saldo do orçamento cai.","en":"But the buses are always full and late. The budget balance is falling."},{"foreign":"Se investirmos mais em metrô e CPTM, melhora. Olha o extrato bancário da cidade.","en":"If we invest more in metro and CPTM, it gets better. Look at the city's bank statement."},{"foreign":"A longo prazo, talvez. Agora está caro. A taxa de juros e o cheque especial estressam as pessoas.","en":"In the long run, maybe. Right now it's expensive. The interest rate and overdraft stress people."},{"foreign":"Verdade. Mesmo assim acho que vale a pena. Dá para fazer uma transferência pro transporte.","en":"True. Even so I think it's worth it. You can make a transfer toward transport."},{"foreign":"Vamos ler mais antes de decidir. Primeiro eu checo a conta corrente no internet banking.","en":"Let's read more before we decide. First I'll check the current account in online banking."},{"foreign":"Ok. A gente se vê depois. PIX, cartão de débito, cartão de crédito, e a conta poupança é outro assunto.","en":"Ok. See you later. PIX, debit card, credit card, and the savings account is another topic."},{"foreign":"E o débito automático do aluguel. O consultor financeiro ajuda com depósito e saque no caixa eletrônico. Senha do cartão e talão de cheques também.","en":"And direct debit for rent. The financial advisor helps with deposit and withdrawal at the ATM. Card PIN and chequebook too."}],"glosses":{"tarifas bancárias":"bank fees","financiamento imobiliário":"mortgage","saldo":"balance","extrato bancário":"bank statement","taxa de juros":"interest rate","cheque especial":"overdraft","transferência":"bank transfer","conta corrente":"current account","internet banking":"online banking","PIX":"PIX (instant payment)","cartão de débito":"debit card","cartão de crédito":"credit card","conta poupança":"savings account","débito automático":"direct debit","consultor financeiro":"financial advisor","depósito":"deposit","saque":"withdrawal","caixa eletrônico":"ATM","senha do cartão":"PIN code","talão de cheques":"chequebook"}},{"id":"pt-planos","title":"Planos para o verão","subtitle":"Summer plans","trail":"double-black-diamond","categoryId":"pt","sentences":[{"foreign":"O que você vai fazer neste verão?","en":"What are you going to do this summer?"},{"foreign":"Quero viajar algumas semanas, se der. Você tem planos?","en":"I want to travel a few weeks, if it works out. Do you have plans?"},{"foreign":"Talvez pro Nordeste. Preciso de bilhete de ida e volta e cartão de embarque no app.","en":"Maybe to the Northeast. I need a return ticket and a boarding pass in the app."},{"foreign":"Você tem passaporte biométrico? A bagagem passa pelo despacho de bagagem e pela alfândega.","en":"Do you have a biometric passport? Luggage goes through baggage check-in and customs."},{"foreign":"Sim. Só um carrinho de bagagem para a bagagem de mão. O portão de embarque fica depois do controle de segurança e do detector de metais.","en":"Yes. Just a luggage cart for hand luggage. The boarding gate is after security and the metal detector."},{"foreign":"O embarque começa cedo. Depois do pouso, a retirada de bagagem é na esteira de bagagem. Cuidado com a escala e o voo de conexão.","en":"Boarding starts early. After landing, baggage claim is on the carousel. Watch the layover and connecting flight."},{"foreign":"Eu fico e trabalho. A poupança vai pra conta poupança, e a taxa de juros importa.","en":"I'll stay and work. Savings go into the savings account, and the interest rate matters."},{"foreign":"Chato? Ou prático? O voo pode ser um voo atrasado. O saguão de embarque e o saguão de desembarque vão estar cheios.","en":"Boring? Or practical? The flight can be a delayed flight. The departures and arrivals halls will be full."},{"foreign":"Prático. Me avisa quando pousar. O ônibus do aeroporto e o balcão de informações ajudam.","en":"Practical. Let me know when you land. The airport shuttle and information desk help."},{"foreign":"Ok. Se quiser vir depois. Duty free e terminal são fáceis de achar. Até logo!","en":"Ok. If you want to join later. Duty free and the terminal are easy to find. See you!"}],"glosses":{"bilhete de ida e volta":"return ticket","cartão de embarque":"boarding pass","passaporte biométrico":"biometric passport","despacho de bagagem":"baggage check-in","alfândega":"customs","carrinho de bagagem":"luggage cart","portão de embarque":"boarding gate","controle de segurança":"security check","detector de metais":"metal detector","retirada de bagagem":"baggage claim","esteira de bagagem":"baggage carousel","escala":"layover","voo de conexão":"connecting flight","conta poupança":"savings account","taxa de juros":"interest rate","voo atrasado":"delayed flight","saguão de embarque":"departures hall","saguão de desembarque":"arrivals hall","ônibus do aeroporto":"airport shuttle","balcão de informações":"information desk","duty free":"duty-free shop","terminal":"terminal"}}]);
